    source_path: path,
    kind: SMOKE_KIND,
    stage: SMOKE_STAGE,
    summary: passed ? "Deterministic smoke test passed." : "Deterministic smoke test failed.",
  })

  await saveManifest(manifest)
  await saveArtifactRegistry(registry)
  return artifact.path
}

