    handoff_allowed = not blocking_reasons and verification_status["verification_passed"] and "handoff-brief" in completed_stage_names

    payload = {
        "repair_plan": {
            "repo_root": str(repo_root),
            "required_follow_on_stages": required_follow_on,
            "replaced_surfaces": replaced_surfaces,
